import java.util.Arrays;

public class Solution {

    private static final long MOD = 1000000007L;

    // Modular exponentiation: (base^exp) % mod
    private static long power(long base, long exp) {
        long res = 1;
        base %= MOD;
        while (exp > 0) {
            if (exp % 2 == 1) {
                res = (res * base) % MOD;
            }
            base = (base * base) % MOD;
            exp /= 2;
        }
        return res;
    }

    // Modular inverse using Fermat's Little Theorem: a^(mod-2) % mod
    private static long modInverse(long n) {
        return power(n, MOD - 2);
    }

    // Class to handle combinations calculation
    private static class Combinatorics {
        private final long[] fact;
        private final long[] invFact;
        private final int maxN;

        public Combinatorics(int maxN) {
            this.maxN = maxN;
            this.fact = new long[maxN + 1];
            this.invFact = new long[maxN + 1];

            fact[0] = 1;
            for (int i = 1; i <= maxN; i++) {
                fact[i] = (fact[i - 1] * i) % MOD;
            }

            invFact[maxN] = modInverse(fact[maxN]);
            for (int i = maxN - 1; i >= 0; i--) {
                invFact[i] = (invFact[i + 1] * (i + 1)) % MOD;
            }
        }

        // Calculates nCk % MOD
        public long C(int n, int k) {
            if (k < 0 || k > n) {
                return 0;
            }

            // C(n, k) = n! / (k! * (n-k)!)
            long num = fact[n];
            long den = (invFact[k] * invFact[n - k]) % MOD;
            return (num * den) % MOD;
        }
    }

    public static long solve(long n_long, long pos_long, long k_long) {
        if (n_long == 0) return 0;

        // Since N <= 10^5, we can safely cast inputs to int for array indexing and iteration, 
        // but we keep the parameters as long for signature compliance.
        int n = (int) n_long;
        int pos = (int) pos_long;
        int k = (int) k_long;

        // L_count: number of people to the left of pos (0 to pos-1)
        int L_count = pos;
        // R_count: number of people to the right of pos (pos+1 to n-1)
        int R_count = n - 1 - pos;

        // Check if K is reachable at all
        if (k < 0 || k > L_count + R_count) {
            return 0;
        }

        // Precompute combinations up to N-1 (since we only need combinations on L_count + R_count = N-1)
        // We use N as max size for convenience, though N-1 would suffice for factorials used.
        Combinatorics combinations = new Combinatorics(n);

        long totalWaysOthers = 0;

        // We need l + r = k, where l is count from left, r is count from right.

        // Determine valid range for l:
        // 1. l >= 0
        // 2. l <= L_count
        // 3. r = k - l >= 0  => l <= k
        // 4. r = k - l <= R_count => l >= k - R_count

        int L_min = Math.max(0, k - R_count);
        int L_max = Math.min(L_count, k);

        for (int l = L_min; l <= L_max; l++) {
            int r = k - l;

            // Ways to get exactly l visible from the left: C(L_count, l)
            long waysL = combinations.C(L_count, l);

            // Ways to get exactly r visible from the right: C(R_count, r)
            long waysR = combinations.C(R_count, r);

            // Contribution for this (l, r) pair
            long contribution = (waysL * waysR) % MOD;

            totalWaysOthers = (totalWaysOthers + contribution) % MOD;
        }

        // The person at 'pos' can choose 'L' or 'R', contributing a factor of 2.
        long finalAnswer = (totalWaysOthers * 2) % MOD;

        return finalAnswer;
    }
}

