public class Solution {

    private static final long MOD = 1000000007;

    // Static fields for precomputed factorials/inverse factorials
    private static long[] fact;
    private static long[] invFact;
    private static int maxNPrecomputed = 0;

    /**
     * Modular exponentiation: (base^exp) % mod
     */
    private static long power(long base, long exp) {
        long res = 1;
        base %= MOD;
        while (exp > 0) {
            if (exp % 2 == 1) res = (res * base) % MOD;
            base = (base * base) % MOD;
            exp /= 2;
        }
        return res;
    }

    /**
     * Modular inverse using Fermat's Little Theorem: a^(MOD-2) % MOD
     */
    private static long modInverse(long n) {
        return power(n, MOD - 2);
    }

    /**
     * Initializes the global factorial and inverse factorial arrays up to maxN.
     * Must be called before calling C(n, k) if maxN is larger than previous initialization.
     */
    private static void initializeCombinatorics(int maxN) {
        if (maxN <= maxNPrecomputed) return;

        maxNPrecomputed = maxN;
        fact = new long[maxN + 1];
        invFact = new long[maxN + 1];

        fact[0] = 1;
        for (int i = 1; i <= maxN; i++) {
            fact[i] = (fact[i - 1] * i) % MOD;
        }

        invFact[maxN] = modInverse(fact[maxN]);
        for (int i = maxN - 1; i >= 0; i--) {
            invFact[i] = (invFact[i + 1] * (i + 1)) % MOD;
        }
    }

    /**
     * Calculates nCk % MOD
     */
    private static long C(int n, int k) {
        if (k < 0 || k > n) {
            return 0;
        }

        // Ensure combinatorics tables are large enough
        if (n > maxNPrecomputed) {
             // This should ideally not happen if initializeCombinatorics is called correctly in solve
             // But we handle it defensively.
             throw new IllegalArgumentException("N exceeds precomputed limit.");
        }

        // C(n, k) = n! / (k! * (n-k)!)
        long num = fact[n];
        long den = (invFact[k] * invFact[n - k]) % MOD;
        return (num * den) % MOD;
    }


