/**
 * Modular exponentiation: (base^exp) % mod
 */
const power = (base, exp, mod) => {
    let res = 1;
    base %= mod;
    while (exp > 0) {
        if (exp % 2 === 1) res = (res * base) % mod;
        base = (base * base) % mod;
        exp = Math.floor(exp / 2);
    }
    return res;
};

/**
 * Modular inverse using Fermat's Little Theorem: a^(mod-2) % mod
 */
const modInverse = (n, mod) => {
    return power(n, mod - 2, mod);
};

class Combinatorics {
    constructor(maxN, mod) {
        this.MOD = mod;
        this.fact = new Array(maxN + 1);
        this.invFact = new Array(maxN + 1);
        this.fact[0] = 1;
        for (let i = 1; i <= maxN; i++) {
            this.fact[i] = (this.fact[i - 1] * i) % mod;
        }
        this.invFact[maxN] = modInverse(this.fact[maxN], mod);
        for (let i = maxN - 1; i >= 0; i--) {
            this.invFact[i] = (this.invFact[i + 1] * (i + 1)) % mod;
        }
    }

    // Calculates nCk % MOD
    C(n, k) {
        if (k < 0 || k > n) {
            return 0;
        }
        if (k === 0 || k === n) {
            return 1;
        }
        if (k > n / 2) {
            k = n - k;
        }

        // C(n, k) = n! / (k! * (n-k)!)
        let num = this.fact[n];
        let den = (this.invFact[k] * this.invFact[n - k]) % this.MOD;
        return (num * den) % this.MOD;
    }
}


function solve(n, pos, k) {
    const MOD = 1000000007;

    if (n === 0) return 0; 

    // Handle the case where K is impossible to reach given the constraints
    // L_count = pos
    const L_count = pos;
    // R_count = n - 1 - pos
    const R_count = n - 1 - pos;

    if (k < 0 || k > L_count + R_count) {
        return 0;
    }

    // Precompute combinations up to N
    const combinations = new Combinatorics(n, MOD);

    let totalWaysOthers = 0;

    // Iterate over l: number of visible people from the left side (L_count)
    // We need l + r = k, so r = k - l.

    // Constraints on l:
    // 1. 0 <= l <= L_count (l must be possible from the left)
    // 2. 0 <= k - l <= R_count (r must be possible from the right)
    //    k - l >= 0  => l <= k
    //    k - l <= R_count => l >= k - R_count

    const L_min = Math.max(0, k - R_count);
    const L_max = Math.min(L_count, k);

    for (let l = L_min; l <= L_max; l++) {
        const r = k - l;

        // Ways to choose l visible from left: C(L_count, l)
        const waysL = combinations.C(L_count, l);

        // Ways to choose r visible from right: C(R_count, r)
        const waysR = combinations.C(R_count, r);

        // Contribution for this (l, r) pair
        const contribution = (waysL * waysR) % MOD;

        totalWaysOthers = (totalWaysOthers + contribution) % MOD;
    }

    // The person at 'pos' can choose 'L' or 'R' independently, contributing a factor of 2.
    // This is valid even if N=1 (where L_count=0, R_count=0, totalWaysOthers=1).
    let finalAnswer = (totalWaysOthers * 2) % MOD;

    return finalAnswer;
}
